const incoming = $json.body ?? $json;
let body = incoming;

if (typeof body === 'string') {
  try { body = JSON.parse(body); } catch (e) {}
}

if (!body || typeof body !== 'object' || Array.isArray(body)) {
  throw new Error('Payload body must be an object');
}

const required = ['event_name', 'email', 'name', 'setup_url', 'expires_at'];
for (const key of required) {
  if (!body[key]) throw new Error(`Missing ${key}`);
}

return { json: body };

